#include <iostream>
#include <memory>
#include <vector>

// Define Parent and Child. Parent owns its children via
// std::vector<std::shared_ptr<Child>>; each Child points back at its Parent.
// Choose the back-pointer type so the objects are actually destroyed (no leak).
// Each destructor prints "<Type> <id> destroyed".

int main()
{
    int pid{};
    int n{};
    std::cin >> pid >> n;

    // Create the parent (shared_ptr) and an independent weak_ptr<Parent> watch.
    // Read n child ids; for each, make a shared_ptr<Child>, set its weak
    // back-pointer to the parent, and have the parent take ownership of it.
    // Then print the counts, observe through each child, and release the parent.

    return 0;
}

solution_code:
#include <iostream>
#include <memory>
#include <vector>
struct Parent;
struct Child {
    int id;
    std::weak_ptr<Parent> parent;
    Child(int id): id{id} {}
    ~Child(){ std::cout << "Child " << id << " destroyed\n"; }
};
struct Parent {
    int id;
    std::vector<std::shared_ptr<Child>> children;
    Parent(int id): id{id} {}
    ~Parent(){ std::cout << "Parent " << id << " destroyed\n"; }
};
int main(){
    int pid{}, n{};
    std::cin >> pid >> n;
    auto parent = std::make_shared<Parent>(pid);
    for(int i=0;i<n;++i){
        int cid; std::cin >> cid;
        auto c = std::make_shared<Child>(cid);
        c->parent = parent;
        parent->children.push_back(c);
    }
    std::weak_ptr<Parent> watch{ parent };
    std::cout << "owners of parent: " << parent.use_count() << '\n';
    for(const auto& c : parent->children){
        if(auto p = c->parent.lock())
            std::cout << "child " << c->id << " sees parent: " << p->id << '\n';
    }
    std::cout << std::boolalpha;
    std::cout << "watch expired before: " << watch.expired() << '\n';
    parent.reset();
    std::cout << "watch expired after: " << watch.expired() << '\n';
    return 0;
}

